import Foundation

@Observable
final class AlarmWheelModel {

    var selectedValue: Decimal
    let values: [Decimal]

    let radiationType: RadiationType

    init(initialValue: Decimal, radiationType: RadiationType, values: [Decimal]) {
        self.selectedValue = initialValue
        self.radiationType = radiationType
        self.values = values
    }

}

extension AlarmWheelModel {
    static let mock: AlarmWheelModel = .init(initialValue: 3, radiationType: .radiationLevel(.countRate), values: [0, 1, 2, 3, 4, 5, 6, 7, 8])
}
```

This is a simple Observable view model class that manages the state for an alarm wheel picker interface, storing a selected value, a list of possible values, and a radiation type.
